class TestSessionTouch:
    def test_touch_updates_timestamp(self, minimal_session):
        old_updated = minimal_session.updated_at
        time.sleep(0.01)  # small delay to ensure time difference
        minimal_session.touch()
        # updated_at should be >= old value
        if isinstance(minimal_session.updated_at, str):
            assert minimal_session.updated_at >= old_updated
        else:
            assert minimal_session.updated_at >= old_updated

    def test_touch_only_modifies_updated_at(self, minimal_session):
        original_id = minimal_session.id
        original_phase = minimal_session.current_phase
        original_round = minimal_session.current_round
        original_posture = minimal_session.posture
        original_status = minimal_session.status
        original_created = minimal_session.created_at

        minimal_session.touch()

        assert minimal_session.id == original_id
        assert minimal_session.current_phase == original_phase
        assert minimal_session.current_round == original_round
        assert minimal_session.posture == original_posture
        assert minimal_session.status == original_status
        assert minimal_session.created_at == original_created

    def test_touch_timestamp_is_utc(self, minimal_session):
        minimal_session.touch()
        updated = minimal_session.updated_at
        if isinstance(updated, datetime):
            assert updated.tzinfo is not None
            assert updated.tzinfo == timezone.utc


