    def test_serialization_roundtrip_stable(self):
        """Session.from_json(session.to_json()) == session (roundtrip stability)."""
        s = make_session(
            posture=Posture.skeptic,
            current_phase="challenge",
            current_round=2,
            conversation_history=[make_message()],
            problem_model=make_problem_model(system_description="test"),
        )
        json_str = s.to_json()
        restored = Session.from_json(json_str)

        assert restored.id == s.id
        assert restored.posture == s.posture
        assert restored.current_phase == s.current_phase
        assert restored.current_round == s.current_round
        assert restored.schema_version == s.schema_version
        assert restored.status == s.status
        assert len(restored.conversation_history) == len(s.conversation_history)
        assert restored.problem_model.system_description == s.problem_model.system_description

